@spec vm_lane_drag_spec  src=tests/specs/vm_lane_drag_spec.lua  loc=528  sha=dee8c7b  cases=18
@exercises trackerView (h.vm), midiManager (h.fm), trackerManager (h.tm)
@surface   vm:setGridSize, vm:moveLaneEvent, fm:dump, tm:addEvent, tm:flush, tm:assignEvent, vm:addLaneEvent, vm:deleteLaneEvent, vm:cycleLaneShape, vm:setLaneTension
@harness   mk{seed.ccs, seed.notes}

# Intent
  Pins vm:moveLaneEvent: row-typed write surface for cc/pb/at events
  driven by the lane-strip drag in renderManager.
  
  Invariants:
    - integer toRow → ppq = rowToPPQ(toRow), ppqL = toRow * logPerRow
    - identity-by-index survives the post-flush rebuild, because:
        * tm sorts col.events by ppq each rebuild
        * the move clamps newppq strictly inside (prev.ppq, next.ppq) by ±1
    - fractional toRow (shift-drag) lands ppq off-grid; ppqL
      records the authored fractional row so reswing remembers it
    - non cc/pb/at columns are silently ignored

# Helpers
  @fn findCcCol(vm, ccNum)  @ 15-19

# Cases
  @case 'integer toRow lands ppq on rowToPPQ exactly; identity-by-index preserved'  [harness]  @ 24-49
  @case 'toRow past previous event clamps to prev.ppq + 1'  [harness]  @ 53-71
  @case 'toRow past next event clamps to next.ppq - 1'  [harness]  @ 75-93
  @case 'fractional toRow (shift-drag) lands ppq off-grid'  [harness]  @ 97-117
  @case 'non-cc/pb/at column is a no-op'  [harness]  @ 121-137
  @case 'val updates without ppq change when toRow matches current row'  [harness]  @ 141-159
  @case 'real pb drags past hidden fake pb at lane-1 note seat'  [harness]  @ 169-217
  @case 'real pb dropped exactly on hidden fake pb seat — fake gets promoted, no loss'  [harness]  @ 228-271
  @case 'pb drag preserves shape and tension'  [harness]  @ 279-313
  @case 'addLaneEvent between two events inherits prev shape, returns idx 2'  [harness]  @ 323-349
  @case 'addLaneEvent before first event has no prev → idx 1, nil shape'  [harness]  @ 353-372
  @case 'addLaneEvent on non-renderable col is a no-op'  [harness]  @ 376-389
  @case 'deleteLaneEvent removes the named visible event'  [harness]  @ 395-416
  @case 'deleteLaneEvent on non-renderable col is a no-op'  [harness]  @ 420-435
  @case 'cycleLaneShape advances shape on the named visible event'  [harness]  @ 442-461
  @case 'cycleLaneShape on non-renderable col is a no-op'  [harness]  @ 465-479
  @case 'setLaneTension writes tension and forces shape=bezier'  [harness]  @ 486-508
  @case 'setLaneTension on non-renderable col is a no-op'  [harness]  @ 512-526

